import { SALAMOBILE_WIDTH, SALAMOBILE_HEIGHT, SALAMOBILE_BG } from "./dimensions";
export { SALAMOBILE_WIDTH, SALAMOBILE_HEIGHT, SALAMOBILE_BG } from "./dimensions";

export default function SalaMobile({ className = "", live = false, noReserve = false, flashColors, flashMode = "bulb", ctaVariant = "default" }: SalaMobileProps): JSX.Element {
  const {
    phase, shown, prog, count, participants, myBids, totalBids, bidAmount, bidder, pressed, flash,
  } = useLiveAuction(live, noReserve);

  // Estado del bid actual en idle (interactivo con el botón "Bidear")
  const [idleBid, setIdleBid] = useState(6559);
  const [idleBidder, setIdleBidder] = useState("ZAE389");
  const [idleFlash, setIdleFlash] = useState(0);

  const progVariant: ProgressBarVariant = live ? (phase === "streaming" || phase === "result" || phase === "activity" || phase === "bestbid" ? "rainbow" : "white") : "rainbow";
  const ctaAmount = (live ? bidAmount : idleBid) + STEP; // CTA = siguiente bid (un poco mayor)

  // Click en "Bidear" (idle): pujo yo → sube mi bid + anima el bid actual
  function handleBid(): void {
    if (live) return;
    setIdleBid((b) => b + STEP);
    setIdleBidder(ME);
    setIdleFlash((f) => f + 1);
  }

  // ── Variante "overlay": ciclo tipo casino ──────────────────────────────────
  // Arranca "big" (CTA gigante, ProgressBar oculto). Cada puja MÍA lo achica y
  // muestra el ProgressBar llenándose ~2.4s; al terminar, vuelve a agrandarse.
  // A la 3ra puja del ciclo, además de rellenarse reinicia el contador.
  const myBidTrigger = live ? myBids : idleFlash;
  const lastBidTrigger = useRef(myBidTrigger);
  const [overlayBig, setOverlayBig] = useState(true);
  const [overlayCycle, setOverlayCycle] = useState(0); // 0,1,2 pujas dentro del ciclo actual
  const overlayTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(
    function driveOverlayCycle() {
      if (ctaVariant !== "overlay") return;
      if (myBidTrigger === lastBidTrigger.current) return;
      lastBidTrigger.current = myBidTrigger;

      if (overlayTimer.current !== null) clearTimeout(overlayTimer.current);
      setOverlayBig(false); // se achica de inmediato + libera el ProgressBar animado
      overlayTimer.current = setTimeout(() => {
        setOverlayBig(true); // vuelve a agrandarse
        setOverlayCycle((c) => (c + 1) % 3); // 3ra puja del ciclo → reinicia a 0
      }, 2400);
    },
    [ctaVariant, myBidTrigger],
  );

  useEffect(
    function resetOverlayOnVariantChange() {
      if (ctaVariant !== "overlay") {
        if (overlayTimer.current !== null) clearTimeout(overlayTimer.current);
        setOverlayBig(true);
        setOverlayCycle(0);
      }
      return () => {
        if (overlayTimer.current !== null) clearTimeout(overlayTimer.current);
      };
    },
    [ctaVariant],
  );

  // overlay "big" (sin puja reciente) → ProgressBar oculto; overlay "shrink"
  // (tras una puja) → ProgressBar visible y animándose. Otras variantes: siempre visible.
  const hideProgress = ctaVariant === "overlay" && overlayBig;
  // Espacio reservado al pie del panel por variante (stream/status terminan ahí,
  // el ProgressBar vive 28px arriba de ese borde): default 108, hero más alto
  // (130, cabe el botón de 76px sin invadir el stream ni la barra), overlay usa
  // más espacio cuando está "big" (botón de 88px) y el default cuando "shrink".
  const ctaReserve = ctaVariant === "hero" ? 130 : ctaVariant === "overlay" ? (overlayBig ? 156 : 108) : 108;

  return (
    <div
      className={className}
      data-block="testsala2-mobile"
      style={{
        position: "relative",
        width: SALAMOBILE_WIDTH,
        height: SALAMOBILE_HEIGHT,
        background: SALAMOBILE_BG,
        overflow: "hidden",
      }}
    >
      {/* Header 420×95 — pills dinámicas: mis bids (live) · bid totales · participantes */}
      <div style={{ position: "absolute", top: 0, left: 0 }}>
        <MobileHeader
          myBids={live ? String(myBids) : "11"}
          totalBids={live ? String(totalBids) : "111"}
          people={live ? String(participants) : "18"}
          reservePill={phase === "bestbid"}
        />
      </div>

      {/* Panel glass del chat — llega hasta abajo. Le reservamos al pie el espacio
          exacto que necesita el CTA de cada variante (ctaReserve) para que el
          stream de mensajes y el ProgressBar nunca queden tapados. */}
      <div style={{ position: "absolute", top: MOBILEHEADER_HEIGHT, left: 0 }}>
        <MobileChatPanel
          height={SALAMOBILE_HEIGHT - MOBILEHEADER_HEIGHT}
          live={live}
          phase={phase}
          shown={shown}
          progress={live ? prog : 40}
          progressVariant={progVariant}
          count={count}
          bidAmount={live ? bidAmount : idleBid}
          bidder={live ? bidder : idleBidder}
          flash={live ? flash : idleFlash}
          flashColors={flashColors}
          flashMode={flashMode}
          ctaReserve={ctaReserve}
          hideProgress={hideProgress}
        />
      </div>

      {/* CTA — siguiente bid (bid actual + paso); se "presiona" con mi puja. Se oculta
          al terminar la subasta (Procesando / Tabla de posiciones). 3 variantes:
          · default — full-width, 60px.
          · hero — XL 76px con más espacio propio reservado (no tapa nada).
          · overlay — arranca gigante (88px) sin ProgressBar visible; cada puja lo
            achica a 60px ~2.4s mientras la barra aparece y se llena, luego vuelve
            a agrandarse (a la 3ra puja el ciclo se reinicia). */}
      <style suppressHydrationWarning dangerouslySetInnerHTML={{ __html: CTA_STYLES }} />
      {phase === "processing" || phase === "result" || phase === "activity" || phase === "bestbid" ? null : (
        <div
          className={[
            "salamobile-cta",
            `salamobile-cta--${ctaVariant}`,
            ctaVariant === "overlay" ? `salamobile-cta--overlay-${overlayBig ? "big" : "shrink"}` : "",
            pressed ? "salamobile-cta--pressed" : "",
          ].filter(Boolean).join(" ")}
          style={{
            position: "absolute",
            left: ctaVariant === "hero" || (ctaVariant === "overlay" && overlayBig) ? 8 : 12,
            right: ctaVariant === "hero" || (ctaVariant === "overlay" && overlayBig) ? 8 : 12,
            bottom: 12,
            display: "flex",
            alignItems: "center",
          }}
        >
          <Button variant="primary" onClick={handleBid}>{fmtMoney(ctaAmount)}</Button>
        </div>
      )}

      {/* Indicadores del ciclo overlay — 3 puntos "tipo casino": se llenan con
          cada puja y marcan cuándo el CTA volverá a agrandarse. */}
      {ctaVariant === "overlay" && phase !== "processing" && phase !== "result" && phase !== "activity" && phase !== "bestbid" ? (
        <div
          style={{
            position: "absolute",
            left: "50%",
            bottom: 78,
            transform: "translateX(-50%)",
            display: "flex",
            gap: 6,
            zIndex: 8,
            transition: "bottom 320ms cubic-bezier(0.3,0,0,1), opacity 260ms ease",
            opacity: overlayBig ? 0 : 1,
          }}
        >
          {[0, 1, 2].map((i) => (
            <span
              key={i}
              style={{
                width: 6,
                height: 6,
                borderRadius: "50%",
                background: i <= overlayCycle ? "#F4AC59" : "rgba(255,255,255,0.3)",
                boxShadow: i <= overlayCycle ? "0 0 6px rgba(244,172,89,0.8)" : "none",
                transition: "background 200ms ease, box-shadow 200ms ease",
              }}
            />
          ))}
        </div>
      ) : null}
    </div>
  );
}

/**
 * useSala — motor de la animación "Ver live" compartido por SalaMobile y
 * SalaDesktop/BidChat.
 *
 * Máquina de estados: idle → welcome → extended → streaming → processing →
 * result → activity. Centraliza timers y estado para que ambos bloques rendericen
 * la misma secuencia. Conectar `onBid` con el backend real se hace aquí.
 */

"use client";

import { useEffect, useRef, useState } from "react";
import type { Phase } from "./liveData";
import {
  STREAM,
  REVEAL_AT,
  TOTAL_STREAM,
  VMC_START,
  VMC_FILL,
  WELCOME_MS,
  EXTENDED_MS,
  RESTART_PAUSE,
  PROCESSING_MS,
  RESULT_MS,
  START_COUNT,
  PARTICIPANTS_TARGET,
  BASE,
} from "./liveData";

export interface LiveAuction {
  phase: Phase;
  count: number;
  participants: number;
  myBids: number;
  totalBids: number;
  shown: number;
  prog: number;
  bidAmount: number;
  bidder: string;
  pressed: boolean;
  flash: number;
  /** Segundos transcurridos desde que empezó el live ("INICIÓ HACE") */
  elapsed: number;
}

/** Formatea segundos → "HH:MM:SS". */
export function fmtElapsed(total: number): string {
  const p = (n: number): string => String(n).padStart(2, "0");
  return `${p(Math.floor(total / 3600))}:${p(Math.floor((total % 3600) / 60))}:${p(total % 60)}`;
}

export function useLiveAuction(live: boolean, noReserve = false): LiveAuction {
  const [phase, setPhase] = useState<Phase>("idle");
  const [count, setCount] = useState(START_COUNT);
  const [participants, setParticipants] = useState(0);
  const [myBids, setMyBids] = useState(0);
  const [totalBids, setTotalBids] = useState(0);
  const [shown, setShown] = useState(0);
  const [prog, setProg] = useState(40);
  const [bidAmount, setBidAmount] = useState(BASE);
  const [bidder, setBidder] = useState("ZAE389");
  const [pressed, setPressed] = useState(false);
  const [flash, setFlash] = useState(0);
  const [elapsed, setElapsed] = useState(0);
  const timers = useRef<ReturnType<typeof setTimeout>[]>([]);
  const elapsedTimer = useRef<ReturnType<typeof setInterval> | null>(null);

  useEffect(
    function runLive() {
      function clearAll(): void {
        timers.current.forEach((id) => {
          clearTimeout(id);
          clearInterval(id);
        });
        timers.current = [];
      }
      function clearElapsed(): void {
        if (elapsedTimer.current !== null) {
          clearInterval(elapsedTimer.current);
          elapsedTimer.current = null;
        }
      }

      if (!live) {
        clearAll();
        clearElapsed();
        setPhase("idle");
        setParticipants(0);
        setShown(0);
        setProg(40);
        setPressed(false);
        setElapsed(0);
        return;
      }

      let cancelled = false;

      // "INICIÓ HACE" corre desde 00:00:00 durante todo el live; su timer va aparte
      // para sobrevivir a los clearAll() de las transiciones de fase.
      setElapsed(0);
      clearElapsed();
      elapsedTimer.current = setInterval(() => setElapsed((e) => e + 1), 1000);

      function cycle(): void {
        if (cancelled) return;
        clearAll();
        // (1)+(2) Recibiendo / Inicio extendido — barra BLANCA full · cuenta de 3s
        setPhase("welcome");
        setShown(0);
        setProg(100);
        setCount(START_COUNT);
        setParticipants(0);
        setMyBids(0);
        setTotalBids(0);
        setBidAmount(BASE);
        setBidder("—");

        timers.current.push(setInterval(() => setParticipants((p) => (p < PARTICIPANTS_TARGET ? p + 1 : p)), 300));
        timers.current.push(setInterval(() => setCount((c) => (c > 1 ? c - 1 : 1)), 1000));
        timers.current.push(
          setTimeout(() => {
            setPhase("extended");
            setCount(START_COUNT); // reinicia la cuenta de 3s para "inicio extendido"
          }, WELCOME_MS),
        );

        timers.current.push(
          setTimeout(function toStreaming() {
            clearAll();
            // (3) Streaming — barra rainbow VACÍA hasta el remate
            setPhase("streaming");
            setShown(0);
            setProg(0);

            STREAM.forEach(function schedule(m, i) {
              timers.current.push(
                setTimeout(function reveal() {
                  setShown(i + 1);
                  if (m.kind === "proposal") {
                    setBidAmount(m.amount ?? BASE);
                    setBidder(m.bidder ?? "—");
                    setFlash((f) => f + 1); // anima el bid actual con cada puja
                    if (m.mine) {
                      setMyBids((x) => x + 1);
                      setTotalBids((x) => x + 1);
                      setPressed(true);
                      timers.current.push(setTimeout(() => setPressed(false), 200));
                    } else {
                      setTotalBids((x) => x + 1);
                    }
                  }
                }, REVEAL_AT[i]),
              );
            });

            // El ProgressBar solo se llena durante el remate (A la una/dos/tres)
            timers.current.push(
              setTimeout(function startFill() {
                const s = Date.now();
                const iv = setInterval(() => {
                  const p = Math.min(100, ((Date.now() - s) / VMC_FILL) * 100);
                  setProg(p);
                  if (p >= 100) clearInterval(iv);
                }, 100);
                timers.current.push(iv);
              }, VMC_START),
            );

            // Fin del remate → Procesando ("Un momento por favor", barra vacía). De ahí:
            //   · Con precio reserva → "bestbid" ("Mejor postor / ¿Deseas mejorarlo?").
            //     El sub-flujo (deseas mejorar → ingresar monto → confirmar → 48 horas)
            //     lo maneja MobileChatPanel localmente (son interacciones del usuario).
            //   · Sin precio reserva → Tabla de posiciones (result) → Actividad.
            timers.current.push(
              setTimeout(function toProcessing() {
                clearAll();
                setPhase("processing");
                setProg(0);
                timers.current.push(
                  setTimeout(function afterProcessing() {
                    if (noReserve) {
                      // Con precio reserva: entra al sub-flujo "Mejor postor".
                      setPhase("bestbid");
                      setProg(100);
                      return;
                    }
                    // Sin reserva: Tabla (barra 100%, 5s) → Actividad.
                    setPhase("result");
                    setProg(100);
                    timers.current.push(setTimeout(() => setPhase("activity"), RESULT_MS));
                  }, PROCESSING_MS),
                );
              }, TOTAL_STREAM + RESTART_PAUSE),
            );
          }, WELCOME_MS + EXTENDED_MS),
        );
      }

      cycle();
      return function cleanup() {
        cancelled = true;
        clearAll();
        clearElapsed();
      };
    },
    [live],
  );

  return { phase, count, participants, myBids, totalBids, shown, prog, bidAmount, bidder, pressed, flash, elapsed };
}

"use client";

/**
 * ProgressBar — Generado por Concorde
 * Fuente: Figma VOYAGER · "Progressbar - Tiempo de bid" (3182:12947)
 *
 * Barra de progreso (track hundido): top recto, esquinas inferiores redondeadas
 * (radio 13), fondo negro 22% con inner-shadows. El relleno (`value` 0-100) usa
 * la gradiente primary (white → #F4AC59 → #8460E5 → white · VYStrokes1). Copia
 * del SVG. Solo `value` — sin estilos editables.
 */

import type { JSX } from "react";

export type ProgressBarVariant = "default" | "rainbow" | "white";

export interface ProgressBarProps {
  /** Progreso 0-100 (default 60) */
  value?: number;
  /** Relleno: "default" (gradiente primary), "rainbow" (white→magenta→rosa) o "white" (blanco sólido). Default "default". */
  variant?: ProgressBarVariant;
  /**
   * Duración (ms) de la transición de ancho al cambiar `value`. Si se omite usa
   * la del CSS (0.3s). Útil para animar un llenado continuo (p. ej. 3000ms lineal).
   */
  transitionMs?: number;
  "aria-label"?: string;
  className?: string;
}

const STYLE_ID = "concorde-progressbar-styles";

const PROGRESSBAR_STYLES = `
.pprogbar {
  position: relative;
  width: 100%;
  height: 22px;
  border-radius: 0 0 13px 13px;
  overflow: hidden;
  background: rgba(0,0,0,0.22);
  box-shadow: inset 0 1px 0 rgba(255,255,255,0.06), inset 0 2px 4px rgba(0,0,0,0.35);
}
.pprogbar__fill {
  position: absolute;
  left: 0;
  top: 0;
  height: 100%;
  background: linear-gradient(135deg, #FFFFFF 0%, #F4AC59 22%, #8460E5 74.5%, #FFFFFF 100%);
  transition: width 0.3s cubic-bezier(0.3,0,0,1);
}
/* Rainbow horizontal (no diagonal): white → lila → magenta → rosa */
.pprogbar__fill--rainbow {
  background: linear-gradient(90deg, #FFFFFF 0%, #F2CCFF 25%, #CC00FF 60%, #FF0066 100%);
  box-shadow: 0 0 6px rgba(255,255,255,0.8), 0 0 14px rgba(204,0,255,0.9), 0 0 30px rgba(255,0,102,0.5);
}
/* Blanco sólido (fases de carga: recibiendo participantes / inicio extendido) */
.pprogbar__fill--white {
  background: #ffffff;
  box-shadow: 0 0 6px rgba(255,255,255,0.7);
}
@media (prefers-reduced-motion: reduce) { .pprogbar__fill { transition: none; } }
`;

let _stylesInjected = false;

export default function ProgressBar({
  value = 60,
  variant = "default",
  transitionMs,
  "aria-label": ariaLabel,
  className = "",
}: ProgressBarProps): JSX.Element {
  if (typeof document !== "undefined" && !_stylesInjected) {
    if (!document.getElementById(STYLE_ID)) {
      const el = document.createElement("style");
      el.id = STYLE_ID;
      el.textContent = PROGRESSBAR_STYLES;
      document.head.appendChild(el);
    }
    _stylesInjected = true;
  }

  const clamped = Math.max(0, Math.min(100, value));

  return (
    <>
      <style id={`${STYLE_ID}-ssr`} suppressHydrationWarning dangerouslySetInnerHTML={{ __html: PROGRESSBAR_STYLES }} />
      <div
        className={`pprogbar ${className}`.trim()}
        role="progressbar"
        aria-valuenow={clamped}
        aria-valuemin={0}
        aria-valuemax={100}
        aria-label={ariaLabel ?? "Tiempo de bid"}
      >
        <div
          className={`pprogbar__fill ${variant !== "default" ? `pprogbar__fill--${variant}` : ""}`.trim()}
          style={{ width: `${clamped}%`, ...(transitionMs != null ? { transition: `width ${transitionMs}ms linear` } : {}) }}
        />
      </div>
    </>
  );
}

