}
.psec-sm:active {
  --vss-angle: 160deg;
  --vss-stop-a: var(--vmc-color-vault-700, #3b1782);
  --vss-stop-b: var(--vmc-color-vault-900, #22005c);
  color: #d1d5dc;
  transform: scale(0.97) translateY(1px);
